import React, { useState, useEffect } from 'react';
import api, { formatCurrency, formatDate, statusLabel } from '../../utils/api';
import { useToast } from '../../context/ToastContext';

const ALL_STATUSES = ['created','pending_payment','paid','packaged','shipped','delivered','cancelled'];

export default function AdminOrdersPage() {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState('');
  const [selected, setSelected] = useState(null);
  const { addToast } = useToast();

  useEffect(() => { loadOrders(); }, [statusFilter]);

  const loadOrders = async () => {
    setLoading(true);
    try {
      const params = statusFilter ? `?status=${statusFilter}` : '';
      const res = await api.get(`/orders${params}`);
      setOrders(res.data.orders);
    } catch { addToast('Không thể tải đơn hàng', 'error'); }
    finally { setLoading(false); }
  };

  const updateStatus = async (orderID, status) => {
    try {
      await api.put(`/orders/${orderID}/status`, { status });
      addToast('Cập nhật thành công!', 'success');
      loadOrders();
      setSelected(null);
    } catch (err) { addToast(err.response?.data?.message || 'Lỗi', 'error'); }
  };

  const cancelOrder = async (orderID) => {
    if (!window.confirm('Hủy đơn hàng này?')) return;
    try {
      await api.delete(`/orders/${orderID}/cancel`);
      addToast('Đơn hàng đã hủy', 'info');
      loadOrders();
      setSelected(null);
    } catch (err) { addToast(err.response?.data?.message || 'Lỗi', 'error'); }
  };

  return (
    <div className="page">
      <div className="page-header">
        <h1>📋 Quản lý đơn hàng</h1>
        <p>Xem và cập nhật trạng thái tất cả đơn hàng</p>
      </div>

      <div className="filter-bar">
        <button className={`btn btn-sm ${!statusFilter ? 'btn-primary' : 'btn-secondary'}`} onClick={() => setStatusFilter('')}>
          Tất cả
        </button>
        {ALL_STATUSES.map(s => (
          <button
            key={s}
            className={`btn btn-sm ${statusFilter === s ? 'btn-primary' : 'btn-secondary'}`}
            onClick={() => setStatusFilter(s)}
          >
            {statusLabel[s]}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="loading"><div className="spinner" /></div>
      ) : (
        <div className="card">
          <div className="table-wrap">
            <table>
              <thead>
                <tr>
                  <th>Mã đơn</th><th>Khách hàng</th><th>Trạng thái</th>
                  <th>Thanh toán</th><th>Giao hàng</th><th>Giá trị</th><th>Ngày đặt</th><th>Hành động</th>
                </tr>
              </thead>
              <tbody>
                {orders.map(o => (
                  <tr key={o.orderID}>
                    <td style={{ fontFamily: 'Syne', fontWeight: 700 }}>#{o.orderID}</td>
                    <td>{o.customerName}</td>
                    <td><span className={`badge badge-${o.status}`}>{statusLabel[o.status]}</span></td>
                    <td><span className={`badge badge-${o.paymentStatus || 'pending'}`}>{o.paymentStatus || '—'}</span></td>
                    <td><span className={`badge badge-${o.deliveryStatus || 'pending'}`}>{o.deliveryStatus || '—'}</span></td>
                    <td style={{ fontFamily: 'Syne', fontWeight: 700, color: 'var(--accent)' }}>{formatCurrency(o.totalAmount)}</td>
                    <td style={{ color: 'var(--text-muted)', fontSize: 12 }}>{formatDate(o.orderDate)}</td>
                    <td>
                      <button className="btn btn-secondary btn-sm" onClick={() => setSelected(o)}>Chi tiết</button>
                    </td>
                  </tr>
                ))}
                {orders.length === 0 && (
                  <tr><td colSpan={8} style={{ textAlign: 'center', color: 'var(--text-muted)', padding: 32 }}>Không có đơn hàng</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {selected && (
        <div className="modal-overlay" onClick={() => setSelected(null)}>
          <div className="modal" style={{ maxWidth: 560 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <div className="modal-title">Đơn hàng #{selected.orderID}</div>
              <button className="modal-close" onClick={() => setSelected(null)}>×</button>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8, marginBottom: 16, fontSize: 13 }}>
              <div><span style={{ color: 'var(--text-muted)' }}>Khách hàng:</span> {selected.customerName}</div>
              <div><span style={{ color: 'var(--text-muted)' }}>Ngày đặt:</span> {formatDate(selected.orderDate)}</div>
              <div><span style={{ color: 'var(--text-muted)' }}>Địa chỉ:</span> {selected.shippingAddress}</div>
              <div><span style={{ color: 'var(--text-muted)' }}>Tổng tiền:</span> <strong style={{ color: 'var(--accent)' }}>{formatCurrency(selected.totalAmount)}</strong></div>
            </div>
            <div style={{ marginBottom: 16 }}>
              <div style={{ fontSize: 12, color: 'var(--text-muted)', marginBottom: 8, textTransform: 'uppercase' }}>Cập nhật trạng thái</div>
              <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                {ALL_STATUSES.filter(s => s !== 'cancelled').map(s => (
                  <button
                    key={s}
                    className={`btn btn-sm ${selected.status === s ? 'btn-primary' : 'btn-secondary'}`}
                    onClick={() => updateStatus(selected.orderID, s)}
                    disabled={selected.status === s}
                  >
                    {statusLabel[s]}
                  </button>
                ))}
              </div>
            </div>
            {!['delivered','cancelled'].includes(selected.status) && (
              <button className="btn btn-danger btn-sm" onClick={() => cancelOrder(selected.orderID)}>
                🗑 Hủy đơn hàng
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
